import{_ as i,o as e,c as l,a3 as s}from"./chunks/framework.CRbjHCyB.js";const k=JSON.parse('{"title":"Compilation","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/design/compilation.md","filePath":"zh/clice/design/compilation.md"}'),t={name:"zh/clice/design/compilation.md"};function n(o,a,r,p,c,h){return e(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="compilation" tabindex="-1">Compilation <a class="header-anchor" href="#compilation" aria-label="Permalink to &quot;Compilation&quot;">​</a></h1><h2 id="增量解析" tabindex="-1">增量解析 <a class="header-anchor" href="#增量解析" aria-label="Permalink to &quot;增量解析&quot;">​</a></h2><p>每当你修改代码时，clice 都必须重新解析文件。clice 使用一种叫做 preamble 的机制实现增量编译。Preamble 是 <a href="https://clang.llvm.org/docs/PCHInternals.html" target="_blank" rel="noreferrer">Precompiled Header</a> 的一种特殊情况——它将文件开头的预处理指令（<code>#include</code> 块）构建成 PCH 缓存在磁盘上。后续解析时直接加载 PCH，跳过 preamble 部分。</p><p>例如：</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;iostream&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> () {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::cout </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Hello world!&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::endl;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>iostream</code> 头文件展开后约有 2 万行代码。clice 会先把 <code>#include &lt;iostream&gt;</code> 构建成 PCH 文件，后续重新解析的代码量就只剩 5 行。除非你修改了 preamble 部分的代码（增删 include），才需要重建 PCH。</p><h3 id="新鲜度检测" tabindex="-1">新鲜度检测 <a class="header-anchor" href="#新鲜度检测" aria-label="Permalink to &quot;新鲜度检测&quot;">​</a></h3><p>PCH 的新鲜度通过两层机制检查：</p><ol><li><strong>mtime 检查</strong> — 快速路径：如果没有依赖文件的 mtime 比缓存的 PCH 更新，则仍然有效。</li><li><strong>内容哈希</strong> — 如果 mtime 发生了变化（例如 <code>touch</code> 但没有实际修改），则哈希文件内容。只有哈希不同时才重建 PCH。</li></ol><p>这避免了仅时间戳变化（构建系统常见的原地重新生成文件）时的昂贵重建。</p><h2 id="多进程流水线" tabindex="-1">多进程流水线 <a class="header-anchor" href="#多进程流水线" aria-label="Permalink to &quot;多进程流水线&quot;">​</a></h2><p>编译任务分布在多个工作进程中：</p><ul><li><strong>无状态工作进程</strong>处理 PCH 构建、PCM 构建（C++20 模块）、补全和签名帮助。这些是临时性的——请求之间不保持状态。</li><li><strong>有状态工作进程</strong>在内存中持有已解析的 AST，服务查询（hover、semantic tokens、inlay hints 等）。文件通过 LRU 淘汰机制缓存。</li></ul><p>主进程不直接执行编译。它分发任务并通过 stdin/stdout 上的 bincode IPC 收集结果。</p><h2 id="c-20-模块" tabindex="-1">C++20 模块 <a class="header-anchor" href="#c-20-模块" aria-label="Permalink to &quot;C++20 模块&quot;">​</a></h2><p>模块编译遵循依赖图（<code>CompileGraph</code>）。主进程从语法级的 <code>DependencyGraph</code> 解析模块依赖，然后通过无状态工作进程按拓扑排序构建 PCM 文件。</p><p>每个模块单元在编译图中有一个 <code>CompileUnit</code>，包含：</p><ul><li>引用计数（兴趣计数），追踪有多少下游依赖需要它</li><li>取消令牌，当引用计数归零时触发</li></ul><p>当文件被修改时，依赖的模块单元会按依赖顺序自动重新编译。</p><h2 id="取消编译" tabindex="-1">取消编译 <a class="header-anchor" href="#取消编译" aria-label="Permalink to &quot;取消编译&quot;">​</a></h2><p>clice 使用<strong>基于兴趣计数的取消</strong>来避免在不再需要的编译上浪费 CPU。</p><h3 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h3><p>在模块 DAG 如 <code>A → B → C</code> 中，如果用户打开文件 C，编译会依次启动 A、B、C。但如果用户在 A 还在构建时关闭了 C（或切换到另一个文件），继续构建 B 和 C 是没有意义的。</p><h3 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to &quot;机制&quot;">​</a></h3><p>编译图中的每个 <code>CompileUnit</code> 维护一个引用计数：</p><ul><li>当文件需要某个模块的 PCM 时，增加（<code>acquire</code>）该模块的引用计数。</li><li>当不再需要时（文件关闭、编辑被取代），减少（<code>release</code>）引用计数。</li><li>当引用计数归零时，触发一个单 tick 的宽限期。如果宽限期后仍为零，则触发编译的取消令牌。</li></ul><p>宽限期防止抖动——快速的打开/关闭序列不会导致冗余的取消-重启循环。</p><h3 id="取代逻辑" tabindex="-1">取代逻辑 <a class="header-anchor" href="#取代逻辑" aria-label="Permalink to &quot;取代逻辑&quot;">​</a></h3><p>当文件在其先前的编译仍在进行时被编辑，旧的构建会被&quot;取代&quot;——其兴趣被释放，新的构建开始。旧的工作进程任务观察到取消令牌后提前终止。</p>`,29)])])}const m=i(t,[["render",n]]);export{k as __pageData,m as default};
